// Java 25 exam prep - Pattern matching for switch
// Learn: branch by type in a switch and refine with a when guard.
String describe(Object value) {
    return switch (value) {
        case Integer i when i < 0 -> "negative int"; // guarded pattern
        case Integer i -> "int " + i;
        case String s -> "text of length " + s.length();
        case null -> "nothing";
        default -> "other";
    };
}
